<section class="section"><div class="container"><h1>Cases & Investigations</h1><?php if (!empty($cases)): ?><div class="case-list"><?php foreach ($cases as $c): ?><article class="case-card"><a href="/cases/<?= h($c['slug'] ?? $c['case_number']) ?>"><h3><?= h($c['title']) ?></h3><span class="badge status-<?= h($c['status'] ?? 'unknown') ?>"><?= h(ucfirst($c['status'] ?? 'Unknown')) ?></span></a></article><?php endforeach; ?></div><?php else: ?><p>No cases yet.</p><?php endif; ?></div></section>
